UPDATE public.articulos SET metadata = '{"areas": ["carácter", "creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior", "Sala"], "cantidad": "04 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "clan", "compañía", "manada", "tropa"], "objetivos": ["Desarrollar la capacidad cognitiva", "Estimular la agilidad", "Estimular la agilidad mental"], "materiales": ["Dados", "Guantes de cocina", "Regalos envueltos"], "variaciones": "Una variación puede ser hacer lo mismo con los ojos vendados, mientras que la o el jugador que le seguiría en turno le indica el resultado de los dados.", "recomendaciones": "El o la moderadora debe estar atento a que los jugadores no lancen los dados más de una vez o indique un resultado que no corresponde para tener el regalo antes de tiempo.\r\n\r\nDe la misma manera se debe poner especial atención en la forma en que se entregan los regalos y guantes de un jugador a otro, debe ser rápido pero con precaución de que no haya un golpe.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_regalosYGuantes.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Comprometiéndome con mi propio crecimiento personal y participando activamente del grupo al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Carácter", "texto": "Actúo consecuentemente con los valores que me inspiran.", "unidad": "Clan", "como_se_cumple": "Asumiendo el liderazgo de mi propio desarrollo y comprometiéndome en el servicio a la comunidad al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de la patrulla al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Siendo honesto con mis compañeros y reconociendo mis errores con sinceridad al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Jugando limpio y diciendo siempre la verdad, asumiendo las consecuencias sin miedo, al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de la patrulla al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Debatiendo con respeto, proponiendo ideas creativas y concertando opiniones diversas en el grupo al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Asumiendo el liderazgo de mi propio desarrollo y comprometiéndome en el servicio a la comunidad al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo mis ideas de forma constructiva y respetando los acuerdos tomados en el consejo al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan dados para ganar el turno."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en mi patrulla para lograr metas comunes al intentar abrir un regalo envuelto usando guantes de cocina mientras los demás lanzan