UPDATE public.articulos SET metadata = '{"areas": ["afectividad", "carácter", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada"], "objetivos": ["Fomentar la comunicación e interpretación", "Fomentar la comunicación en el grupo", "Fomentar un entorno de confianza", "Permitir el contacto físico"], "materiales": ["Pañolin"], "variaciones": "Puede hacer lo mismo con otras partes del cuerpo, como la nariz, los pies, las mejillas, etc.", "recomendaciones": "Haga las siguientes preguntas al finalizar ¿Qué sensaciones experimentaron? ¿Hubo resistencias a hacer este juego? ¿Qué tipo de reflexiones surgieron?", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Desarrolla el autoconocimiento, la confianza grupal y la empatía en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ManoConMano.png", "objetivos_educativos": [{"id": "6e25f6ed-277c-41b4-9d0f-322b0a2d4c94", "area": "Afectividad", "texto": "Acepto las opiniones de mis compañeros, aunque yo piense distinto.", "unidad": "Manada", "como_se_cumple": "Ayudando con alegría a mis compañeros de seisena para divertirnos y aprender juntos al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "c8993915-0234-464c-934e-2a09f8c4338e", "area": "Afectividad", "texto": "Digo lo que pienso sin ofender o insultar a mis compañeros ni burlarme de ellos.", "unidad": "Manada", "como_se_cumple": "Trabajando en equipo con mi seisena, valorando el esfuerzo del grupo por sobre el mío al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "2f8359db-221e-4a64-b2df-2b3e7b74a2db", "area": "Afectividad", "texto": "Escucho las opiniones de las demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Compañía", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "3621f4ae-1316-4b3e-8682-3e3c9ad381a7", "area": "Afectividad", "texto": "Mantengo mi opinión cuando estoy convencida que es correcta.", "unidad": "Compañía", "como_se_cumple": "Expresando mis puntos de vista con madurez y escuchando de forma activa a mis compañeros al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "a4060c60-7ce9-425b-bf2a-76941a689937", "area": "Afectividad", "texto": "Escucho las opiniones de los demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Tropa", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "4ade9c82-6b0d-4a44-8bc6-2eb47a011ffb", "area": "Afectividad", "texto": "Digo lo que pienso con respeto hacia los demás personas.", "unidad": "Tropa", "como_se_cumple": "Fortaleciendo la toma de decisiones compartida, la empatía y la autodisciplina en el grupo al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "6c2b5054-70e8-4529-957f-a8abea073918", "area": "Afectividad", "texto": "Expreso mis opiniones libremente, sin descalificar a los demás.", "unidad": "Avanzada", "como_se_cumple": "Debatiendo con respeto, proponiendo ideas creativas y concertando opiniones diversas en el grupo al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Siendo honesto con mis compañeros y reconociendo mis errores con sinceridad al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Jugando limpio y diciendo siempre la verdad, asumiendo las consecuencias sin miedo, al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de la patrulla al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de la patrulla al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Comprometiéndome con mi propio crecimiento personal y participando activamente del grupo al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma amistosa con mi seisena al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo el valor de las reglas del juego limpio, aceptando ganar o perder con alegría, al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando las normas de convivencia grupales y proponiendo mejoras de manera democrática al desplazarse en cadena manteniendo contacto físico continuo con sus compañeros y superando obstáculos."}]}'::jsonb WHERE id = 'cfb5d456-9514-45e1-a62d-e47ca7d9d8e8';
