UPDATE public.articulos SET metadata = '{"areas": ["afectividad", "carácter", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior", "Interior", "Sala"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["compañía", "avanzada", "clan"], "objetivos": ["Conocer a los demás", "Fomentar un entorno de confianza"], "materiales": ["Listado de temas"], "variaciones": "Puede agregar una dificultad haciendo que quienes corrieron al centro del círculo justifiquen su relación con el valor o característica con algún ejemplo de su vida.\r\n\r\nOtra variación es que cuando vayan hacia el centro lo hagan con la actitud que para ellos represente el valor o característica.", "recomendaciones": "Celebre cada acercamiento al centro del círculo, no cuestione en exceso la definición propia de las y los jóvenes.", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Desarrolla el autoconocimiento, la confianza grupal y la empatía en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_NuestrasCualidades.png", "objetivos_educativos": [{"id": "2f8359db-221e-4a64-b2df-2b3e7b74a2db", "area": "Afectividad", "texto": "Escucho las opiniones de las demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Compañía", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al reflexionar y compartir las fortalezas y virtudes individuales de sus compañeros de patrulla en un ambiente de confianza."}, {"id": "3621f4ae-1316-4b3e-8682-3e3c9ad381a7", "area": "Afectividad", "texto": "Mantengo mi opinión cuando estoy convencida que es correcta.", "unidad": "Compañía", "como_se_cumple": "Expresando mis puntos de vista con madurez y escuchando de forma activa a mis compañeros al reflexionar y compartir las fortalezas y virtudes individuales de sus compañeros de patrulla en un ambiente de confianza."}, {"id": "6c2b5054-70e8-4529-957f-a8abea073918", "area": "Afectividad", "texto": "Expreso mis opiniones libremente, sin descalificar a los demás.", "unidad": "Avanzada", "como_se_cumple": "Debatiendo con respeto, proponiendo ideas creativas y concertando opiniones diversas en el grupo al reflexionar y compartir las fortalezas y virtudes individuales de sus compañeros de patrulla en un ambiente de confianza."}, {"id": "d0ba748f-313b-4ffe-b2a3-fb21c1f8943f", "area": "Afectividad", "texto": "Practico una conducta asertiva y una actitud afectuosa hacia las demás personas, sin inhibiciones ni agresividad.", "unidad": "Clan", "como_se_cumple": "Viviendo mi compromiso de fe de manera coherente con mi proyecto de vida y servicio al prójimo al reflexionar y compartir las fortalezas y virtudes individuales de sus compañeros de patrulla en un ambiente de confianza."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de la patrulla al reflexionar y compartir las fortalezas y virtudes individuales de sus compañeros de patrulla en un ambiente de confianza."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al reflexionar y compartir las fortalezas y virtudes individuales de sus compañeros de patrulla en un ambiente de confianza."}, {"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Comprometiéndome con mi propio crecimiento personal y participando activamente del grupo al reflexionar y compartir las fortalezas y virtudes individuales de sus compañeros de patrulla en un ambiente de confianza."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Carácter", "texto": "Actúo consecuentemente con los valores que me inspiran.", "unidad": "Clan", "como_se_cumple": "Asumiendo el liderazgo de mi propio desarrollo y comprometiéndome en el servicio a la comunidad al reflexionar y compartir las fortalezas y virtudes individuales de sus compañeros de patrulla en un ambiente de confianza."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al reflexionar y compartir las fortalezas y virtudes individuales de sus compañeros de patrulla en un ambiente de confianza."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al reflexionar y compartir las fortalezas y virtudes individuales de sus compañeros de patrulla en un ambiente de confianza."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando las normas de convivencia grupales y proponiendo mejoras de manera democrática al reflexionar y compartir las fortalezas y virtudes individuales de sus compañeros de patrulla en un ambiente de confianza."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilid