UPDATE public.articulos SET metadata = '{"areas": ["carácter", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "compañía", "manada", "tropa"], "objetivos": ["Desarrollar el carácter mediante la cooperación", "Estimular la creatividad", "Trabajo en equipo"], "materiales": "", "variaciones": "Una variación posible es cambiar sólo un trozo entre cada equipo, es decir, de la fotografía A se toma un trozo y se coloca en B, de la B se toma un trozo y se coloca en C, y así según cuantas fotografías haya.\r\n\r\nCon esta variación se busca mostrar a los participantes la interdepencia que tienen los equipos unos con otros y no es sino hasta que hablan con otro equipo que podrán resolver la situación.", "recomendaciones": "Procure dejar los trozos vueltos para abajo de forma que el trozo sacado por le participante sea más sorpresivo al ubicarlo en la restauración.\r\n\r\nDeje las reglas muy claras desde un principio, al ser un juego que promueve la creatividad, es necesario establecer el marco de trabajo general.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeLaFotografia.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Comprometiéndome con mi propio crecimiento personal y participando activamente del grupo al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de la patrulla al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Siendo honesto con mis compañeros y reconociendo mis errores con sinceridad al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Jugando limpio y diciendo siempre la verdad, asumiendo las consecuencias sin miedo, al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de la patrulla al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Debatiendo con respeto, proponiendo ideas creativas y concertando opiniones diversas en el grupo al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo mis ideas de forma constructiva y respetando los acuerdos tomados en el consejo al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en mi patrulla para lograr metas comunes al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Divirtiéndome al máximo y compartiendo momentos felices con mis compañeros de seisena al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Desarrollando mi autonomía, compañerismo y sentido de la responsabilidad al correr y recrear una postura o escena fotográfica grupal específica al llegar a la meta del circuito."}, {"id": "49ae6ac6-be8f-