UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior", "Interior", "Sala"], "cantidad": "02 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compañía", "manada", "tropa"], "objetivos": ["Crear un ambiente de distensión", "Desarrollar la motricidad", "Trabajo en equipo"], "materiales": ["Cartulina", "Cartón corrugado", "Papeles de colores", "Pelota"], "variaciones": "Se puede hacer de manera individual o por equipos, también son bienvenidas distintas variaciones a la imaginación como por ejemplo, obstáculos aparte, o diversas condiciones que hagan del juego más dinámico.", "recomendaciones": "Si es para niños pequeños, hay que prestar atención a hacer agujeros lo bastante amplios para no generar frustración o desconcentración hacia la actividad.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_encestarEnElArbolNavideno.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Perfeccionando mis destrezas físicas y adoptando hábitos de entrenamiento y autocuidado al lanzar aros o pelotas para embocarlos en ramas o soportes decorados como árbol navideño."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio físico, la salud integral y la superación de mis propios límites al lanzar aros o pelotas para embocarlos en ramas o soportes decorados como árbol navideño."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando mis habilidades físicas y motrices con esfuerzo y perseverancia al lanzar aros o pelotas para embocarlos en ramas o soportes decorados como árbol navideño."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando mis convicciones de fe y los valores scouts en mi vida cotidiana al lanzar aros o pelotas para embocarlos en ramas o soportes decorados como árbol navideño."}, {"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Agradeciendo a Dios por la naturaleza, los amigos y los momentos felices que compartimos al lanzar aros o pelotas para embocarlos en ramas o soportes decorados como árbol navideño."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Manteniendo hábitos de alimentación y cuidado corporal para proteger mi salud al lanzar aros o pelotas para embocarlos en ramas o soportes decorados como árbol navideño."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Trabajando codo a codo con mi patrulla, apoyando a quienes más lo necesitan en la actividad al lanzar aros o pelotas para embocarlos en ramas o soportes decorados como árbol navideño."}