UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["compañía", "tropa", "avanzada", "clan"], "objetivos": ["Aprendizaje por la acción", "Reforzar el conocimiento"], "materiales": ["Preguntas", "Silbato"], "variaciones": "Puede hacer el juego sin saltos, sólo con el cuerpo a tierra correr y responder la pregunta, cambiando de esta manera el formato de quien es el que gana, siendo la medición en este caso por quien respondió más preguntas correctas.", "recomendaciones": "<ul>\r\n \t<li>Al momento de realizar el cuerpo a tierra, tener énfasis en el cuidado del cuerpo de los demás para no pisarlos.</li>\r\n \t<li>Si la o el participante no puede tirarse al suelo, considerar opciones o variaciones para que puede agacharse o moverse de otra manera si a así se requiere.</li>\r\n \t<li>Preguntas e historia estarán en archivos de descargas y se llevarán impresos para la actividad.</li>\r\n</ul>", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDelSaber.png", "objetivos_educativos": [{"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando mis habilidades físicas y motrices con esfuerzo y perseverancia al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando mis convicciones de fe y los valores scouts en mi vida cotidiana al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Trabajando codo a codo con mi patrulla, apoyando a quienes más lo necesitan en la actividad al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando mis convicciones de fe y los valores scouts en mi vida cotidiana al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Perfeccionando mis destrezas físicas y adoptando hábitos de entrenamiento y autocuidado al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Consolidando el dominio físico, la salud integral y la superación de mis propios límites al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando las normas de convivencia grupales y proponiendo mejoras de manera democrática al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos en mi comunidad al correr hacia puestos de preguntas sobre conocimientos scouts y responder correctamente para avanzar."}]}'::jsonb WHERE id = 'ee69fbc0-4bbe-4cbf-8aab-bea1e11b7e15';
