UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "individual", "duracion": "15 minutos", "unidades": ["avanzada", "clan", "compañía", "manada", "tropa"], "objetivos": ["Conocer las capacidades corporales", "Crear un ambiente de distensión", "Estrategia y planificación", "Promover la elaboración de estrategias"], "materiales": ["Pañolin"], "variaciones": "<strong>Formal</strong>: Esta variación es uno contra uno, en un círculo formado en el suelo, además de perder el pañolin en este caso también se puede perder por salir del círculo. No se puede quitar el pañolin si el oponente está caído en el suelo o de espalda.\r\n\r\n<strong>En equipo</strong>: Los equipos se enfrentan en una especie de cacería y cada vez que dos participantes se encuentran harán una pelea de pañolines, quien pierda entregara su pañolin que será una vida adicional para quién ganó.\r\n\r\n<strong>Flechazo</strong>: También se hace en equipo, sin embargo, habrá un equipo en cada extremo del campo y a la señal cada equipo cruzara el campo para ubicarse donde se encuentra el equipo contrario, en el cruce entre ambos equipos se pueden quitar los pañolines al pasar y sin ser necesariamente uno contra uno, en este caso se puede aprovechar cualquier distracción del oponente para quitarle su pañolin.\r\n\r\n<strong>Ojos Vendados</strong>: Se hace con los ojos vendados y siguiendo las instrucciones del resto de su equipo.\r\n\r\n<strong>Al hombro</strong>: se amarra el pañolin en el hombro con un nudo simple de sacar al tirar de una de las puntas.\r\n\r\n<strong>Al tobillo</strong>: mismo anterior pero el pañolin va amarrado en el tobillo o la pierna\r\n\r\n<strong>A caballo</strong>: Se hace en parejas donde uno se sube arriba del otro, el o la \"caballo\" es quien está debajo y sólo se preocupa de desplazarse y evitar dejar el pañolin del \"jinete\" a merced de la otra pareja, la o el \"jinete\" que está arriba lleva el pañolin y tiene que cuidar su pañolin y tratar de quitar el pañolin contrario.\r\n\r\n<strong>De dragones</strong>: se hace en equipo, en filas tomados de la cintura, la o el primero de la fila debe tratar de quitar el pañolin, y el último de cada fila de protegerlo, no se pueden soltar las filas, si se sueltan pierden.\r\n\r\nEn el barro, en la nieve, saltando en un pie, sosteniendo algo, con una mano, etc, etc, etc.", "recomendaciones": "Procure indicar la importancia sobre el cuidado del cuerpo, y elegir un terreno adecuado para que no ocurran accidentes por golpes, caídas o tropiezos.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_peleaPanolines.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Comprometiéndome con mi propio crecimiento personal y participando activamente del grupo al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Integrando la sustentabilidad y la defensa activa de la naturaleza en mi estilo de vida al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Trabajando codo a codo con mi patrulla, apoyando a quienes más lo necesitan en la actividad al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Cuidando mi bienestar físico, reconociendo mis límites y esforzándome por superarme al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Descubriendo la belleza de la naturaleza y cuidando a los animales y plantas al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Comprendiendo el valor de las reglas del juego limpio, aceptando ganar o perder con alegría, al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Trabajando codo a codo con mi patrulla, apoyando a quienes más lo necesitan en la actividad al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en mi patrulla para lograr metas comunes al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Debatiendo con respeto, proponiendo ideas creativas y concertando opiniones diversas en el grupo al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Asumiendo el liderazgo de mi propio desarrollo y comprometiéndome en el servicio a la comunidad al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo mis ideas de forma constructiva y respetando los acuerdos tomados en el consejo al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en mi patrulla para lograr metas comunes al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Divirtiéndome al máximo y compartiendo momentos felices con mis compañeros de seisena al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Desarrollando mi autonomía, compañerismo y sentido de la responsabilidad al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Debatiendo mis ideas de forma constructiva y respetando los acuerdos tomados en el consejo al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en mi patrulla para lograr metas comunes al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando las normas de convivencia grupales y proponiendo mejoras de manera democrática al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos en mi comunidad al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma amistosa con mi seisena al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo el valor de las reglas del juego limpio, aceptando ganar o perder con alegría, al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al intentar quitar el pañuelo de la espalda de los oponentes mientras se defiende el propio en un área delimitada."}]}'::jsonb WHERE id = '9b62d315-8681-4991-95de-04d87a93f15f';
