UPDATE public.articulos SET metadata = '{"areas": ["carácter", "corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["compañía", "manada", "tropa"], "objetivos": ["Aprender a seguir instrucciones", "Trabajo en equipo"], "materiales": ["Agua", "Botella"], "variaciones": "Una variación de esta actividad se puede hacer cambiando las botella por otro recipiente, por ejemplo una cubeta, de esta forma al tener la boquilla más abierta que una botella es más probable que caiga agua en el traslado del contenedor en lugar de la transferencia del líquido.", "recomendaciones": "Procure evitar esta actividad durante el invierno para que no se mojen los participantes en un mal clima.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeBotellasConAgua.png", "objetivos_educativos": [{"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de la patrulla al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Siendo honesto con mis compañeros y reconociendo mis errores con sinceridad al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Jugando limpio y diciendo siempre la verdad, asumiendo las consecuencias sin miedo, al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Fomentando la integración, el compañerismo y el juego limpio dentro de la patrulla al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Trabajando codo a codo con mi patrulla, apoyando a quienes más lo necesitan en la actividad al transportar botellas llenas de agua sobre la cabeza o en bandejas inestables en una competencia de equilibrio."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que