UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada"], "objetivos": ["Aprender a seguir instrucciones", "Aumentar el conocimiento de las limitantes físicas", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "Una variación es que en lugar de gritar desde el otro lado del campo las instrucciones puede ir una compañera o compañero de equipo al lado del participante que está vendada o vendado para darle las indicaciones.", "recomendaciones": "<ul>\r\n \t<li>Ponga énfasis en el cuidado de la jugadora o jugador cuando le den instrucciones para evitar accidentes.</li>\r\n \t<li>Procure que el terreno sea un terreno parejo para evitar que las y los participantes tropiecen y se caigan.</li>\r\n \t<li>Indique que no es necesario correr y que se debe primero saber que se esta dando un paso seguro.</li>\r\n</ul>", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_RelevosCiegos.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Agradeciendo a Dios por la naturaleza, los amigos y los momentos felices que compartimos al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Manteniendo hábitos de alimentación y cuidado corporal para proteger mi salud al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desafiando mis habilidades físicas y motrices con esfuerzo y perseverancia al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Integrando mis convicciones de fe y los valores scouts en mi vida cotidiana al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Trabajando codo a codo con mi patrulla, apoyando a quienes más lo necesitan en la actividad al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Integrando mis convicciones de fe y los valores scouts en mi vida cotidiana al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Perfeccionando mis destrezas físicas y adoptando hábitos de entrenamiento y autocuidado al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Divirtiéndome al máximo y compartiendo momentos felices con mis compañeros de seisena al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Desarrollando mi autonomía, compañerismo y sentido de la responsabilidad al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Debatiendo mis ideas de forma constructiva y respetando los acuerdos tomados en el consejo al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en mi patrulla para lograr metas comunes al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Debatiendo mis ideas de forma constructiva y respetando los acuerdos tomados en el consejo al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en mi patrulla para lograr metas comunes al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Debatiendo con respeto, proponiendo ideas creativas y concertando opiniones diversas en el grupo al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma amistosa con mi seisena al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo el valor de las reglas del juego limpio, aceptando ganar o perder con alegría, al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando las normas de convivencia grupales y proponiendo mejoras de manera democrática al correr en relevos con los ojos vendados guiados únicamente por la voz de los compañeros de equipo."}]}'::jsonb WHERE id = '6a2b2b30-c8f4-44d1-a766-b02bdd725658';
