UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["compañía", "manada", "tropa"], "objetivos": ["Desarrollar la motricidad", "Desfogue de Energías", "Trabajo en equipo"], "materiales": ["Sin Materiales"], "variaciones": "Una variación de la actividad puede ser tomando las rodillas del que se encuentra delante, en lugar de los tobillos.", "recomendaciones": "Procure poner énfasis en la seguridad del equipo, que tengan cuidado con sus manos a la hora de avanzar, si visualiza que uno o todos los equipos tienen inconvenientes para avanzar haga recomendaciones para que avancen coordinadamente.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeCiempies.png", "objetivos_educativos": [{"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Trabajando codo a codo con mi patrulla, apoyando a quienes más lo necesitan en la actividad al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Cuidando mi bienestar físico, reconociendo mis límites y esforzándome por superarme al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Descubriendo la belleza de la naturaleza y cuidando a los animales y plantas al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Comprendiendo el valor de las reglas del juego limpio, aceptando ganar o perder con alegría, al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Trabajando codo a codo con mi patrulla, apoyando a quienes más lo necesitan en la actividad al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Asumiendo roles de liderazgo o colaboración en mi patrulla para lograr metas comunes al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando con alegría las reglas del juego y compartiendo de forma amistosa con mi seisena al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Comprendiendo el valor de las reglas del juego limpio, aceptando ganar o perder con alegría, al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Respetando los acuerdos y normas de convivencia de mi patrulla para jugar seguro al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Valorando y respetando las normas colectivas como base para el crecimiento del grupo al correr en fila coordinando el paso al estar todos los miembros del equipo tomados de los tobillos o la cintura."}]}'::jsonb WHERE id = '371cbd0d-11e0-47ec-8420-ae021d5bd73e';
