UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Bosque", "Cerro", "Exterior", "Interior", "Montaña", "Río"], "cantidad": "04 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "clan"], "objetivos": ["Estimular la creatividad", "Fomentar el desarrollo del criterio", "Trabajo en equipo"], "materiales": ["Objetos Varios"], "variaciones": "Se puede variar en la cantidad de tiempo establecido, cantidad de participantes por equipo, cantidad de objetos a ser utilizados para lograr la meta, tipos de objetos que NO pueden ser utilizados, el tamaño del lugar en donde se realizará la actividad.", "recomendaciones": "Se requiere precaución a la hora de ocupar los objetos encontrados por los participantes, asegurarse de que estos no sean peligrosos en su uso, o quienes lo ocupen tengan manejo adecuado de estos. También precaución con el terreno en donde se realiza, evitando que existan elementos que puedan dañar físicamente a algún participante", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_macgyverPreparadoParaLaAventura.png", "objetivos_educativos": [{"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Comprometiéndome con mi propio crecimiento personal y participando activamente del grupo al resolver problemas de supervivencia imprevistos utilizando un conjunto limitado de objetos comunes."}, {"id": "29eee8b1-a414-4df9-90e1-520a384fb9aa", "area": "Creatividad", "texto": "Uno los conocimientos teórico y práctico mediante la aplicación constante de mis habilidades técnicas y manuales.", "unidad": "Clan", "como_se_cumple": "Asumiendo el liderazgo de mi propio desarrollo y comprometiéndome en el servicio a la comunidad al resolver problemas de supervivencia imprevistos utilizando un conjunto limitado de objetos comunes."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Respetando las normas de convivencia grupales y proponiendo mejoras de manera democrática al resolver problemas de supervivencia imprevistos utilizando un conjunto limitado de objetos comunes."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Promoviendo la justicia, el respeto cívico y la construcción democrática de acuerdos en mi comunidad al resolver problemas de supervivencia imprevistos utilizando un conjunto limitado de objetos comunes."}]}'::jsonb WHERE id = 'afebb91a-f5bc-49b1-8d00-e8bcf555b4ee';
