UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Bosque", "Campo Abierto", "Exterior"], "cantidad": "08 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Crear un ambiente de distensión", "Perder el miedo a la oscuridad", "Trabajo en equipo"], "materiales": ["Sin Materiales"], "variaciones": "", "recomendaciones": "Previo al juego, deje que las y los participantes revisen el terreno en el que se efectuará la actividad, esto para que reconozcan los lugares en que deben tener más cuidado con sus pisadas y evitar accidentes.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_cazadoresSabuesosVenados.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Comprometiéndome con mi propio crecimiento personal y participando activamente del grupo al rastrear el aroma o huellas de los ''venados'' en un juego de rol de caza en bosque."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Integrando la sustentabilidad y la defensa activa de la naturaleza en mi estilo de vida al rastrear el aroma o huellas de los ''venados'' en un juego de rol de caza en bosque."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se