UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "05 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "compañía", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Desfogue de Energías", "Promover la elaboración de estrategias"], "materiales": ["Sin Materiales"], "variaciones": "Para iniciar el bulldog puede ser uno de los animadores de la actividad y este se retirara del centro del campo del juego cuando ya considere que hay suficientes \"bulldogs\".", "recomendaciones": "Sea claro y está atento a los que se salgan de los límites del campo.\r\n\r\nMucha gente siendo \"Bulldog\" puede causar accidentes, procure mantener un número razonable en el centro del campo de juego.\r\n\r\nHaga énfasis en el cuidado del cuerpo propio y de los demás, esta es una actividad muy física que puede causar accidentes cuando hay mucho entusiasmo en los participantes.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_BulldogIngles.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Comprometiéndome con mi propio crecimiento personal y participando activamente del grupo al esquivar a los tacleadores del centro para cruzar al otro lado del campo sin ser levantado o tocado."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Trabajando codo